+# backends.conf — Single source of truth for CLI backends and model names.
+#
+# Every script that deals with backend/model names MUST source this file
+# and use normalize_model_for_backend() instead of inline sed/regex.
+#
+# Format rules:
+#   claude  → hyphens in version: claude-haiku-4-5, claude-opus-4-6
+#   copilot → dots in version:    claude-haiku-4.5, claude-opus-4.6
+#   others  → pass through unchanged
+#
+# Usage:
+#   source /usr/local/etc/hive/backends.conf   (system)
+#   source "$(dirname "$0")/../config/backends.conf"  (repo-relative)
+#
+#   model=$(normalize_model_for_backend "copilot" "claude-haiku-4-5")
+#   # → claude-haiku-4.5
+#
+#   backend=$(detect_backend_from_model "gpt-5.3-codex")
+#   # → copilot
+
+# ── Supported backends ──────────────────────────────────────────────────
+# BACKEND_NAME  BINARY   PERM_FLAG                    MODEL_FLAG
+KNOWN_BACKENDS="claude copilot gemini codex amazonq goose aider"
+
+# ── Backend → binary mapping ────────────────────────────────────────────
+backend_binary() {
+  case "$1" in
+    claude)  echo "claude" ;;
+    copilot) echo "copilot" ;;
+    gemini)  echo "gemini" ;;
+    codex)   echo "codex" ;;
+    amazonq) echo "q" ;;
+    goose)   echo "goose" ;;
+    aider)   echo "aider" ;;
+    *)       echo "$1" ;;
+  esac
+}
+
+# ── Backend → permission flag ───────────────────────────────────────────
+backend_perm_flag() {
+  case "$1" in
+    claude)  echo "--dangerously-skip-permissions" ;;
+    copilot) echo "--allow-all" ;;
+    gemini)  echo "--yolo" ;;
+    codex)   echo "--full-auto" ;;
+    amazonq) echo "--trust-all-tools" ;;
+    goose)   echo "--no-confirm" ;;
+    aider)   echo "--yes" ;;
+    *)       echo "" ;;
+  esac
+}
+
+# ── Model version format normalization ──────────────────────────────────
+# Claude CLI uses hyphens (claude-haiku-4-5), copilot uses dots (4.5).
+# All other backends pass through unchanged.
+normalize_model_for_backend() {
+  local backend="$1" model="$2"
+  case "$backend" in
+    copilot)
+      # claude-haiku-4-5 → claude-haiku-4.5 (last hyphen before final digit → dot)
+      echo "$model" | sed -E 's/([0-9]+)-([0-9]+)$/\1.\2/'
+      ;;
+    claude)
+      # claude-haiku-4.5 → claude-haiku-4-5 (dot in version → hyphen)
+      echo "$model" | sed -E 's/([0-9]+)\.([0-9]+)$/\1-\2/'
+      ;;
+    *)
+      echo "$model"
+      ;;
+  esac
+}
+
+# ── Detect backend from model name ──────────────────────────────────────
+# gpt-* → copilot, gemini-* → gemini, claude-* → could be either (prefer claude)
+detect_backend_from_model() {
+  local model="$1"
+  case "$model" in
+    gpt-*)    echo "copilot" ;;
+    gemini-*) echo "gemini" ;;
+    claude-*) echo "claude" ;;
+    *)        echo "unknown" ;;
+  esac
+}
+
+# ── Compare models ignoring format differences ─────────────────────────
+# Returns 0 if models are the same after normalizing to claude format.
+models_equal() {
+  local a="$1" b="$2"
+  local na nb
+  na=$(echo "$a" | sed -E 's/([0-9]+)\.([0-9]+)$/\1-\2/')
+  nb=$(echo "$b" | sed -E 's/([0-9]+)\.([0-9]+)$/\1-\2/')
+  [ "$na" = "$nb" ]
+}
+
+# ── Known models (for validation) ───────────────────────────────────────
+# canonical name (claude format)  → tier (for dashboard coloring)
+model_tier() {
+  case "$1" in
+    claude-haiku-4-5*|claude-haiku-4.5*)     echo "haiku" ;;
+    claude-sonnet-4-6*|claude-sonnet-4.6*)   echo "sonnet" ;;
+    claude-opus-4-6*|claude-opus-4.6*)       echo "opus" ;;
+    claude-opus-4-7*|claude-opus-4.7*)       echo "opus" ;;
+    gpt-*)                                    echo "gpt" ;;
+    gemini-*)                                 echo "gemini" ;;
+    *)                                        echo "unknown" ;;
+  esac
+}

